package com.example.sso.controller;

import jakarta.servlet.http.HttpServletRequest;
import jakarta.servlet.http.HttpServletResponse;
import jakarta.servlet.http.HttpSession;
import org.springframework.stereotype.Controller;
import org.springframework.web.bind.annotation.GetMapping;

import java.io.IOException;
import java.net.URI;
import java.net.URISyntaxException;
import java.util.Set;

@Controller
public class LogoutController {

    // Allowlist of trusted domains for redirect after logout
    private static final Set<String> ALLOWED_REDIRECT_HOSTS = Set.of(
            "app1.example.com",
            "app2.example.com",
            "portal.example.com",
            "www.example.com",
            "example.com"
    );

    // Default safe redirect if the 'next' parameter is missing or invalid
    private static final String DEFAULT_REDIRECT = "https://www.example.com/login";

    @GetMapping("/logout")
    public void logout(HttpServletRequest request, HttpServletResponse response) throws IOException {
        // Invalidate the session
        HttpSession session = request.getSession(false);
        if (session != null) {
            session.invalidate();
        }

        String nextUrl = request.getParameter("next");
        String safeRedirectUrl = validateAndSanitizeRedirectUrl(nextUrl);

        response.sendRedirect(safeRedirectUrl);
    }

    /**
     * Validates the redirect URL against an allowlist of trusted hosts.
     * Returns the default redirect URL if validation fails.
     *
     * This prevents open redirect vulnerabilities where an attacker could craft
     * a malicious 'next' parameter pointing to a phishing site, e.g.:
     *   /logout?next=https://evil-site.com/fake-login
     *
     * @param redirectUrl the user-supplied redirect URL
     * @return a validated safe URL, or the default redirect
     */
    private String validateAndSanitizeRedirectUrl(String redirectUrl) {
        if (redirectUrl == null || redirectUrl.isBlank()) {
            return DEFAULT_REDIRECT;
        }

        try {
            URI uri = new URI(redirectUrl);

            // Block URIs with no scheme or non-http(s) schemes (e.g., javascript:, data:, etc.)
            String scheme = uri.getScheme();
            if (scheme == null) {
                // Could be a relative path like "/dashboard" — allow only safe relative paths
                return validateRelativePath(redirectUrl);
            }

            if (!scheme.equalsIgnoreCase("https") && !scheme.equalsIgnoreCase("http")) {
                return DEFAULT_REDIRECT;
            }

            // Validate the host against the allowlist
            String host = uri.getHost();
            if (host == null || !ALLOWED_REDIRECT_HOSTS.contains(host.toLowerCase())) {
                return DEFAULT_REDIRECT;
            }

            // Block userinfo in URI to prevent tricks like https://example.com@evil.com
            if (uri.getUserInfo() != null) {
                return DEFAULT_REDIRECT;
            }

            // Reconstruct the URI to normalize it and prevent encoding tricks
            URI normalizedUri = new URI(
                    uri.getScheme(),
                    null, // no userInfo
                    uri.getHost(),
                    uri.getPort(),
                    uri.getPath(),
                    uri.getQuery(),
                    uri.getFragment()
            );

            return normalizedUri.toASCIIString();

        } catch (URISyntaxException e) {
            // Malformed URI — fall back to default
            return DEFAULT_REDIRECT;
        }
    }

    /**
     * Validates a relative path to ensure it is a safe internal redirect.
     * Only allows paths starting with '/' and not '//' (which browsers may interpret as protocol-relative URLs).
     */
    private String validateRelativePath(String path) {
        // Must start with exactly one '/' and not contain protocol-relative patterns
        if (path.startsWith("/") && !path.startsWith("//") && !path.contains("\\")) {
            // Additional check: ensure no CRLF injection
            if (!path.contains("\r") && !path.contains("\n")) {
                return path;
            }
        }
        return DEFAULT_REDIRECT;
    }
}